1	import { PRESET_DOMAINS } from "./utils";
2	
3	const STORAGE_KEY = "custom_domains";
4	
5	export interface Domain {
6	  name: string;
7	  icon: string;
8	  color: string;
9	}
10	
11	export const UNCATEGORIZED: Domain = { name: "未分类", icon: "📦", color: "#78716c" };
12	
13	function getStoredDomains(): Domain[] {
14	  try {
15	    const stored = localStorage.getItem(STORAGE_KEY);
16	    if (stored) {
17	      const parsed = JSON.parse(stored);
18	      if (Array.isArray(parsed) && parsed.length > 0) {
19	        return parsed;
20	      }
21	    }
22	  } catch {
23	    /* ignore parse errors */
24	  }
25	  return [...PRESET_DOMAINS];
26	}
27	
28	export function getDomains(): Domain[] {
29	  return [...getStoredDomains(), UNCATEGORIZED];
30	}
31	
32	export function saveDomains(doms: Domain[]): void {
33	  localStorage.setItem(STORAGE_KEY, JSON.stringify(doms));
34	}
35	
36	export function resetDomains(): void {
37	  localStorage.removeItem(STORAGE_KEY);
38	}
39

1	export function getToday(): string {
2	  return new Date().toISOString().split("T")[0];
3	}
4	
5	export function formatDate(date: Date | string): string {
6	  return new Date(date).toLocaleDateString("zh-CN", {
7	    year: "numeric",
8	    month: "long",
9	    day: "numeric",
10	    weekday: "long",
11	  });
12	}
13	
14	export const PRESET_DOMAINS = [
15	  { name: "健身", icon: "💪", color: "#ef4444" },
16	  { name: "读书", icon: "📚", color: "#3b82f6" },
17	  { name: "变美", icon: "✨", color: "#ec4899" },
18	  { name: "工作", icon: "💼", color: "#f59e0b" },
19	  { name: "学习", icon: "🧠", color: "#8b5cf6" },
20	  { name: "商业思维", icon: "🏛️", color: "#10b981" },
21	  { name: "视野", icon: "🌍", color: "#06b6d4" },
22	  { name: "生活习惯", icon: "🏠", color: "#78716c" },
23	];
