async function handleDomainSave() {
  const name = domainForm.name.trim();
  if (!name) return;

  const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);

  if (domainManagerView === "new") {
    if (userDomains.some(d => d.name === name)) {
      showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
      return;
    }
    userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
  } else if (domainManagerView === "edit") {
    const idx = userDomains.findIndex(d => d.name === editingDomainName);
    if (idx === -1) return;

    if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
      showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
      return;
    }

    const oldName = userDomains[idx].name;
    userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };

    // If domain renamed, update all habits under old name
    if (name !== oldName) {
      try {
        for (const h of habits.filter(h => h.domainId === oldName)) {
          await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) });
        }
        fetchHabits();
      } catch {
        showToast({ title: "迁移习惯失败", icon: "none" });
        return;
      }
    }
  }

  saveDomains(userDomains);
  setDomainManagerView("list");
  setEditingDomainName(null);
}

