14	function getStoredDomains(): Domain[] {
15	  try {
16	    const stored = localStorage.getItem(STORAGE_KEY);
17	    if (stored) {
18	      const parsed = JSON.parse(stored);
19	      if (Array.isArray(parsed) && parsed.length > 0) {
20	        return parsed;
21	      }
22	    }
23	  } catch {
24	    /* ignore parse errors */
25	  }
26	  return [...PRESET_DOMAINS];
27	}
28	
29	export function getDomains(): Domain[] {
30	  return [...getStoredDomains(), UNCATEGORIZED];
31	}
32	
33	export function saveDomains(doms: Domain[]): void {
34	  try {
35	    localStorage.setItem(STORAGE_KEY, JSON.stringify(doms));
36	  } catch {
37	    showToast({ title: "保存领域失败，存储空间不足", icon: "none" });
38	  }
39	}
40	
41	export function resetDomains(): void {
42	  localStorage.removeItem(STORAGE_KEY);
43	}
